#include <cstddef>

struct list_head {
    list_head* next;
    list_head* prev;
};

void list_init(list_head* head) {
    head->next = head;
    head->prev = head;
}

void list_add(list_head* entry, list_head* head) {
    entry->next = head->next;
    entry->prev = head;
    head->next->prev = entry;
    head->next = entry;
}

#define LIST_ENTRY(ptr, type, member) \
    ((type*)((char*)(ptr) - offsetof(type, member)))
